.container {
  display: flex;
  gap: 1.5rem;
  background: #f0f0f0;
  padding: 1rem;
}
.item {
  background: #42a5f5;
  color: white;
  padding: 1rem;
  border-radius: 4px;
}

.btn-group {
  display: inline-flex;
  gap: 0.5rem;
}
.btn-group button {
  padding: 0.5rem 1rem;
  border: 1px solid #ccc;
  border-radius: 4px;
  background: #fff;
  cursor: pointer;
}
.btn-group button:hover {
  background: #f0f0f0;
}

.media-container {
  display: inline-flex;
  align-items: center;
  gap: 1rem;
  background: #f9f9f9;
  padding: 1rem;
  border-radius: 8px;
  border: 1px solid #ddd;
}
.media-container img {
  border-radius: 50%;
  width: 50px;
  height: 50px;
}
.media-container button {
  padding: 0.5rem 1rem;
  background: #42a5f5;
  color: white;
  border: none;
  border-radius: 4px;
  cursor: pointer;
}
